def {{nama_fungsi}}(endpoint_url, api_key, prompt, model="default-model", timeout=30):
    """Kirim prompt ke API LLM dan kembalikan teks jawabannya."""
    payload = json.dumps({
        "model": model,
        "prompt": prompt
    }).encode("utf-8")
    req = urllib.request.Request(
        endpoint_url,
        data=payload,
        headers={
            "Content-Type": "application/json",
            "Authorization": f"Bearer {api_key}"
        },
        method="POST"
    )
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        data = json.loads(resp.read().decode("utf-8"))
    return data.get("{{response_text_key}}", data)

def {{nama_fungsi}}(func):
    """Decorator: coba ulang func sampai {{max_attempts}}x jika terjadi exception."""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        last_error = None
        for attempt in range(1, {{max_attempts}} + 1):
            try:
                return func(*args, **kwargs)
            except Exception as e:
                last_error = e
                if attempt < {{max_attempts}}:
                    time.sleep({{base_delay}} * attempt)
        raise last_error
    return wrapper

PROVIDER_REGISTRY = {}

def register_provider(name):
    """Decorator untuk mendaftarkan fungsi provider baru ke registry."""
    def decorator(func):
        PROVIDER_REGISTRY[name] = func
        return func
    return decorator


def {{nama_fungsi}}(provider_name, *args, **kwargs):
    """Panggil fungsi provider terdaftar berdasarkan nama string."""
    if provider_name not in PROVIDER_REGISTRY:
        raise ValueError(f"Provider '{provider_name}' belum terdaftar. Tersedia: {list(PROVIDER_REGISTRY)}")
    return PROVIDER_REGISTRY[provider_name](*args, **kwargs)
